class Solution {
public:
    bool canMakeSubsequence(string str1, string str2) {
        int m = str1.size(), n = str2.size();
        for (int i = 0; i < (1 << m); i++) {
            string temp = str1;
            for (int j = 0; j < m; j++) {
                if ((i >> j) & 1) {
                    if (temp[j] == 'z') temp[j] = 'a';
                    else temp[j]++;
                }
            }
            int p1 = 0, p2 = 0;
            while (p1 < m && p2 < n) {
                if (temp[p1] == str2[p2]) p2++;
                p1++;
            }
            if (p2 == n) return true;
        }
        return false;
    }
};
